const response = msg.payload;

if (!response || !response.data) {
    node.warn('No data received from investing.com');
    return null;
}

const data = response.data;
const now = new Date();

const parsed = {
    symbol: 'NQ100',
    price: parseFloat(data.last) || parseFloat(data.price),
    change_value: parseFloat(data.change) || 0,
    change_percent: parseFloat(data.change_percent) || parseFloat(data.changePercent) || 0,
    volume: parseInt(data.volume) || 0,
    open_price: parseFloat(data.open) || 0,
    high_price: parseFloat(data.high) || 0,
    low_price: parseFloat(data.low) || 0,
    close_price: parseFloat(data.close) || 0,
    timestamp: now.toISOString(),
    source: 'investing_com'
};

node.status({ text: `Price: ${parsed.price}, Change: ${parsed.change_percent}%` });

return { payload: parsed };

if (msg.payload.statusCode && msg.payload.statusCode !== 200) {
    node.error('HTTP Error: ' + msg.payload.statusCode + ' - ' + msg.payload.statusMessage);
    // Log failed attempt
    const errorLog = {
        timestamp: new Date().toISOString(),
        source: 'investing_scraper',
        error: msg.payload.statusCode,
        url: msg.url
    };
    node.warn(JSON.stringify(errorLog));
}
return null;

const now = new Date();
const hour = now.getUTCHours();

// US market hours: 14:30 - 21:00 UTC (9:30 AM - 4:00 PM EST)
const isMarketHours = (hour >= 14 && hour < 21);

if (!isMarketHours) {
    node.status({ text: 'Outside market hours - skipping', fill: 'grey', shape: 'ring' });
    return null;
}

return msg;
